// ═══════════════════════════════════════════════════
// 接收 Midas 发布回传的 postId，获取完整文章
// ═══════════════════════════════════════════════════

const pubResult = $input.first().json;

return {
  postId: pubResult.postId || pubResult.id,
  title: pubResult.title || '',
  subreddit: pubResult.subredditName || pubResult.subreddit || '',
  timestamp: new Date().toISOString()
};

// ═══════════════════════════════════════════════════
// 解析 AI 输出 → 按平台拆分
// ═══════════════════════════════════════════════════

const response = $input.first().json;
const raw = response.choices?.[0]?.message?.content || '';

// 按 --- 分割线拆分为各平台内容
const sections = raw.split(/\n---\n/).filter(s => s.trim());

function extractSection(keyword) {
  return sections.find(s => s.includes(keyword))?.trim() || '';
}

const xiaohongshu = extractSection('小红书') || extractSection('📕');
const wechat = extractSection('公众号') || extractSection('微信') || extractSection('📱');
const toutiao = extractSection('头条') || extractSection('知乎') || extractSection('📰');
const tldr = extractSection('核心结论') || extractSection('速览') || extractSection('⚡');

return {
  // 原始信息
  _post_id: $('🔍 提取发布信息').first().json.postId,
  _title: $('🔍 提取发布信息').first().json.title,

  // 各平台分发内容
  xiaohongshu: xiaohongshu,
  wechat_draft: wechat,
  toutiao_dynamic: toutiao,
  core_conclusions: tldr,

  // 元数据
  _raw: raw,
  _tokens: response.usage || {},
  _generated_at: new Date().toISOString()
};

// ═══════════════════════════════════════════════════
// 分发结果汇总
// ═══════════════════════════════════════════════════

const data = $input.first().json;

const summary = {
  pipeline: 'omnichannel-distribution',
  post_id: data._post_id,
  title: data._title,
  generated_at: data._generated_at,
  platforms: {
    xiaohongshu: data.xiaohongshu ? `${data.xiaohongshu.length} chars ✓` : 'not generated',
    wechat_draft: data.wechat_draft ? `${data.wechat_draft.length} chars ✓` : 'not generated',
    toutiao_dynamic: data.toutiao_dynamic ? `${data.toutiao_dynamic.length} chars ✓` : 'not generated',
    core_conclusions: data.core_conclusions ? `${data.core_conclusions.length} chars ✓` : 'not generated'
  },

  // 平台 API 分发状态（未来接入时使用）
  distribution_status: {
    xiaohongshu: 'manual',  // 小红书无公开API，需手动复制粘贴
    wechat: 'manual',        // 公众号需手动粘贴到素材管理
    toutiao: 'manual'        // 头条号需手动粘贴
  }
};

return summary;

// ═══════════════════════════════════════════════════
// 返回分发结果给调用方
// ═══════════════════════════════════════════════════

const data = $('📦 拆分各平台内容').first().json;

return {
  status: 'ok',
  post_id: data._post_id,
  xiaohongshu: data.xiaohongshu,
  wechat_draft: data.wechat_draft,
  toutiao_dynamic: data.toutiao_dynamic,
  core_conclusions: data.core_conclusions
};
